import json

# Load all businesses that accept credit cards
businesses = locals()['var_functions.query_db:20']
print('Found ' + str(len(businesses)) + ' businesses that accept credit cards')

# Dictionary to count categories
category_count = {}
# Dictionary to map category -> list of business_ids
business_ids_by_category = {}

# Process each business
for business in businesses:
    description = business.get('description', '')
    business_id = business.get('business_id', '')

    # Extract categories from description - look for common patterns
    categories = []

    desc_lower = description.lower()

    # Check for different patterns
    if 'services in' in desc_lower:
        # Get text after 'services in'
        parts = description.split('services in', 1)
        if len(parts) > 1:
            cat_text = parts[1].strip()
            # Remove trailing period
            if cat_text.endswith('.'):
                cat_text = cat_text[:-1]
            # Split by comma
            for cat in cat_text.split(','):
                cat = cat.strip()
                if cat:
                    categories.append(cat)
    elif 'including' in desc_lower:
        parts = description.split('including', 1)
        if len(parts) > 1:
            cat_text = parts[1].strip()
            if cat_text.endswith('.'):
                cat_text = cat_text[:-1]
            for cat in cat_text.split(','):
                cat = cat.strip()
                if cat:
                    categories.append(cat)
    elif 'services and products' in desc_lower:
        parts = description.split('fields of', 1)
        if len(parts) > 1:
            cat_text = parts[1].strip()
            if cat_text.endswith('.'):
                cat_text = cat_text[:-1]
            for cat in cat_text.split(','):
                cat = cat.strip()
                if cat:
                    categories.append(cat)
    elif 'premier destination for' in desc_lower:
        parts = description.split('destination for', 1)
        if len(parts) > 1:
            cat_text = parts[1].strip()
            if cat_text.endswith('.'):
                cat_text = cat_text[:-1]
            for cat in cat_text.split(','):
                cat = cat.strip()
                if cat:
                    categories.append(cat)

    # Clean categories (remove 'and' from the last one if present)
    cleaned_categories = []
    for cat in categories:
        if cat.startswith('and '):
            cat = cat[4:]
        elif ' and ' in cat:
            # Split "Category1 and Category2" into separate categories
            subcats = cat.split(' and ')
            for subcat in subcats:
                subcat = subcat.strip()
                if subcat:
                    cleaned_categories.append(subcat)
        else:
            cleaned_categories.append(cat)

    # Count categories and store business IDs
    for category in cleaned_categories:
        category_count[category] = category_count.get(category, 0) + 1
        if category not in business_ids_by_category:
            business_ids_by_category[category] = []
        business_ids_by_category[category].append(business_id)

# Print category counts
print('Category counts (top 20):')
category_list = sorted(category_count.items(), key=lambda x: x[1], reverse=True)
for i in range(min(20, len(category_list))):
    print(category_list[i][0] + ': ' + str(category_list[i][1]))

result = {}
if category_count:
    top_category = max(category_count.items(), key=lambda x: x[1])
    print('\nTop category: ' + top_category[0] + ' with ' + str(top_category[1]) + ' businesses')
    result = {
        'top_category': top_category[0],
        'count': top_category[1],
        'business_ids': business_ids_by_category[top_category[0]]
    }
else:
    result = {'error': 'No categories found'}

print('__RESULT__:')
print(json.dumps(result))

