import json
import re

# Get all businesses that accept credit cards
businesses = locals()['var_functions.query_db:30']
print('Total businesses accepting credit cards:', len(businesses))

# Parse categories from descriptions
category_count = {}
for business in businesses:
    desc = business.get('description', '')
    # Extract category text using regex
    if 'services in' in desc:
        match = re.search(r'services in (.+?)(?:\.|$)', desc)
        if match:
            cats = match.group(1).replace(' and ', ',').split(',')
            for cat in cats:
                cat = cat.strip()
                if cat:
                    category_count[cat] = category_count.get(cat, 0) + 1
    elif 'services, including' in desc:
        match = re.search(r'services, including (.+?)(?:\.|$)', desc)
        if match:
            cats = match.group(1).replace(' and ', ',').split(',')
            for cat in cats:
                cat = cat.strip()
                if cat:
                    category_count[cat] = category_count.get(cat, 0) + 1
    elif 'products in the fields of' in desc:
        match = re.search(r'fields of (.+?)(?:\.|$)', desc)
        if match:
            cats = match.group(1).replace(' and ', ',').split(',')
            for cat in cats:
                cat = cat.strip()
                if cat:
                    category_count[cat] = category_count.get(cat, 0) + 1
    elif 'premier destination for' in desc:
        match = re.search(r'destination for (.+?)(?:\.|$)', desc)
        if match:
            cats = match.group(1).replace(' and ', ',').split(',')
            for cat in cats:
                cat = cat.strip()
                if cat:
                    category_count[cat] = category_count.get(cat, 0) + 1

print('Categories found:', len(category_count))
print('Top 5 categories:')
sorted_cats = sorted(category_count.items(), key=lambda x: x[1], reverse=True)
for i in range(min(5, len(sorted_cats))):
    print('  ', sorted_cats[i][0], ':', sorted_cats[i][1])

# Get top category
top_category = sorted_cats[0]
print('\nTop category:', top_category[0], 'with', top_category[1], 'businesses')

# Build result
result = {
    'top_category': top_category[0],
    'business_count': top_category[1]
}

print('__RESULT__:')
print(json.dumps(result))

