category_count = {}
for b in businesses:
    desc = b.get('description', '')
    cats = []

    # Find category text
    cat_text = ''
    if 'services in ' in desc:
        cat_text = desc.split('services in ')[1]
    elif 'services, including ' in desc:
        cat_text = desc.split('services, including ')[1]
    elif 'fields of ' in desc:
        cat_text = desc.split('fields of ')[1]
    elif 'destination for ' in desc:
        cat_text = desc.split('destination for ')[1]

    if cat_text:
        # Remove period and split
        cat_text = cat_text.replace(' and ', ',')
        if cat_text.endswith('.'):
            cat_text = cat_text[:-1]
        for c in cat_text.split(','):
